async (params, browser) => {
  // Open maker profile
  await browser.open(`https://www.producthunt.com/@${params.username}`)

  // Wait for profile to load
  await browser.waitForSelector('h1, [class*=\'profile\'], [class*=\'user-name\'], [class*=\'hero\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract maker profile
  const maker_data = await browser.evaluate(`const nameEl = document.querySelector('h1, [class*="profile"] h1, [class*="user-name"]'); const bioEl = document.querySelector('[class*="bio"], [class*="about"], [class*="headline"]'); const followersEl = document.querySelector('[class*="followers"] span, [class*="follower-count"]'); const followingEl = document.querySelector('[class*="following"] span'); const avatarEl = document.querySelector('[class*="avatar"] img, [class*="profile"] img'); const products = []; const productEls = document.querySelectorAll('[class*="post-item"], a[href*="/posts/"]'); const seen = new Set(); for (let i = 0; i < Math.min(productEls.length, 10); i++) { const el = productEls[i]; const titleEl = el.querySelector('h3, strong, [class*="title"]'); const href = el.getAttribute('href') || (el.querySelector('a') ? el.querySelector('a').href : ''); if (seen.has(href)) continue; seen.add(href); const taglineEl = el.querySelector('p, [class*="tagline"]'); const upvotesEl = el.querySelector('[class*="vote"] span'); products.push({ name: titleEl ? titleEl.textContent.trim() : '', tagline: taglineEl ? taglineEl.textContent.trim() : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', url: href.startsWith('http') ? href : 'https://www.producthunt.com' + href }); } const socialEls = document.querySelectorAll('a[href*="twitter.com"], a[href*="github.com"], a[href*="linkedin.com"], a[class*="social"]'); const socials = []; socialEls.forEach(function(el) { socials.push(el.href); }); return { name: nameEl ? nameEl.textContent.trim() : '' + params.username + '', bio: bioEl ? bioEl.textContent.trim().substring(0, 500) : '', followers: followersEl ? followersEl.textContent.trim() : '', following: followingEl ? followingEl.textContent.trim() : '', avatar: avatarEl ? avatarEl.getAttribute('src') : '', products: products, social_links: socials.slice(0, 5), profile_url: window.location.href }`)

  return maker_data
}
